INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'sl', 145, 1, NULL, 'Alexander Maclaren em Sl 145:1', 'Alexander Maclaren destaca a coerência doutrinária aplicada à vida cristã. Em Salmos 145, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Alexander Maclaren', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'sl', 146, 1, NULL, 'Basílio de Cesareia em Sl 146:1', 'Na leitura de Basílio de Cesareia, vemos a leitura cristológica e eclesial da passagem. Salmos 146 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Basílio de Cesareia', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'sl', 147, 1, NULL, 'Stephen Charnock em Sl 147:1', 'Segundo Stephen Charnock, a piedade prática e a santificação do coração ilumina o sentido deste texto. Salmos 147 mostra que adoração, sabedoria e temor do Senhor sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Stephen Charnock', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'sl', 148, 1, NULL, 'F. B. Meyer em Sl 148:1', 'Na leitura de F. B. Meyer, vemos a coerência doutrinária aplicada à vida cristã. Salmos 148 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'F. B. Meyer', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'sl', 149, 1, NULL, 'Gregório de Nissa em Sl 149:1', 'Gregório de Nissa interpreta este versículo a partir de a leitura cristológica e eclesial da passagem. Em Salmos 149, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Gregório de Nissa', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'sl', 150, 1, NULL, 'John Flavel em Sl 150:1', 'John Flavel destaca a piedade prática e a santificação do coração. Em Salmos 150, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'John Flavel', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'pv', 1, 1, NULL, 'John Wesley em Pv 1:1', 'Segundo John Wesley, o chamado ao arrependimento, fé viva e missão ilumina o sentido deste texto. Provérbios 1 mostra que adoração, sabedoria e temor do Senhor sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'John Wesley', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'pv', 2, 1, NULL, 'Adam Clarke em Pv 2:1', 'Na leitura de Adam Clarke, vemos a exposição textual com aplicação pastoral objetiva. Provérbios 2 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Adam Clarke', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'pv', 3, 1, NULL, 'João Calvino em Pv 3:1', 'João Calvino interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Provérbios 3, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'João Calvino', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'pv', 4, 1, NULL, 'John Brown of Haddington em Pv 4:1', 'John Brown of Haddington destaca a piedade prática e a santificação do coração. Em Provérbios 4, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
